import DOMPurify from 'dompurify';
import { FormSingleCheckboxControl } from 'src/builder/PublicActionPage/components/CheckboxControl/FormSingleCheckboxControl';
import { Label } from 'src/builder/PublicActionPage/components/Label';
import { Meta } from 'src/builder/PublicActionPage/components/Meta';

export const CommunicationsConsentPhone = ({
  communicationsConsentText,
  name,
}: {
  communicationsConsentText?: string | null;
  name?: string;
}) => {
  const fallbackName = name || 'the organization';
  const defaultDisclaimer = `By providing your phone number, you are consenting to receive text message updates, including automated text messages, to that number from ${fallbackName}. Message & Data rates may apply, and message frequency may vary over time. Reply "STOP" to opt out of these text message updates.`;

  return (
    <div className="flex flex-col items-stretch">
      <FormSingleCheckboxControl
        formControlProps={{ className: 'leading-[17px] mb-0' }}
        name="communicationsConsentPhone"
      >
        <Label variant="regular">Send me updates by text*</Label>
      </FormSingleCheckboxControl>
      <Meta
        className="leading-4 !text-neutral-600"
        dangerouslySetInnerHTML={{
          __html: DOMPurify.sanitize(
            `* ${communicationsConsentText || defaultDisclaimer}`
          ),
        }}
        variant="regular"
      />
    </div>
  );
};
